      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');

const router = express.Router();

router.post('/', async (req, res) => {
  const { projectId } = req.params;
  const { message } = req.body;
  if (!message) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Message is required' } });
  }
  const task = await tasksService.createTask(projectId, message);
  res.status(201).json({ task });
});

router.patch('/:taskId', async (req, res) => {
  const { projectId, taskId } = req.params;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Invalid status' } });
  }
  const task = await tasksService.updateTaskStatus(projectId, taskId, status);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ task });
});

module.exports = router;
