      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');

let tasksStore = [];

const createTask = (projectId, message) => {
  const task = { id: randomUUID(), projectId, message, status: 'todo' };
  tasksStore.push(task);
  return task;
};

const updateTaskStatus = (projectId, taskId, status) => {
  const task = tasksStore.find(t => t.id === taskId && t.projectId === projectId);
  if (task) {
    task.status = status;
  }
  return task;
};

module.exports = {
  createTask,
  updateTaskStatus
};
